import java.util.Map;import java.util.TreeMap;
final class SingletonPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
  static final class ProviderCatalog{private static ProviderCatalog instance;private final Map<String,String>entries=new TreeMap<>();private ProviderCatalog(){}static synchronized ProviderCatalog instance(){if(instance==null)instance=new ProviderCatalog();return instance;}static synchronized void resetForTest(){instance=null;}synchronized void register(String n,String e){String current=entries.get(n);if(current!=null&&!current.equals(e))throw new PatternException("registration_conflict");entries.put(n,e);}synchronized Map<String,String>entries(){return new TreeMap<>(entries);}}
  @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){ProviderCatalog.resetForTest();ProviderCatalog first=ProviderCatalog.instance(),second=ProviderCatalog.instance();for(Map<String,Object>v:(java.util.List<Map<String,Object>>)input.getOrDefault("registrations",java.util.List.of()))first.register(String.valueOf(v.get("name")),String.valueOf(v.get("endpoint")));Map<String,String>entries=second.entries();Map<String,Object>result=new java.util.LinkedHashMap<>();result.put("same_instance",first==second);result.put("entries",entries);result.put("size",entries.size());return result;}}
